import { createContext, useContext } from 'react'

interface NotificationProps {
  heading: string
  subheading: string
  type: string
}

interface UseNotificationResult {
  notify: (props: NotificationProps) => void
}

const useNotification = (): UseNotificationResult => {
  const notificationContext = useContext(NotificationContext)

  if (!notificationContext) {
    throw new Error('useNotification must be used within a NotificationContext')
  }

  return {
    notify: async (props: NotificationProps) => {
      if (!notificationContext.element) return

      const { heading, subheading, type } = props
      await notificationContext.element.open({
        heading,
        subheading,
        type,
      })
    },
  }
